package observability

import (
	"fmt"
	"text/template"

	ngfAPIv1alpha2 "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha2"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
)

var (
	tmpl            = template.Must(template.New("observability policy").Parse(observabilityTemplate))
	tmplInternal    = template.Must(template.New("observability policy internal").Parse(internalTemplate))
	tmplExtRedirect = template.Must(template.New("observability policy ext redirect").Parse(externalRedirectTemplate))
)

const observabilityTemplate = `
{{- if .Tracing }}
otel_trace {{ .Strategy }};
  {{- if .Tracing.Context }}
otel_trace_context {{ .Tracing.Context }};
  {{- end }}
  {{- if .Tracing.SpanName }}
otel_span_name "{{ .Tracing.SpanName }}";
  {{- end }}
  {{- range $attr := .Tracing.SpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
  {{- range $attr := .GlobalSpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
{{- end }}
`

const internalTemplate = `
{{- if .Tracing }}
  {{- if .Tracing.SpanName }}
otel_span_name "{{ .Tracing.SpanName }}";
  {{- else }}
otel_span_name $request_uri_path;
  {{- end }}
  {{- range $attr := .Tracing.SpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
  {{- range $attr := .GlobalSpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
{{- end }}
`

const externalRedirectTemplate = `
{{- if .Tracing }}
otel_trace {{ .Strategy }};
  {{- if .Tracing.Context }}
otel_trace_context {{ .Tracing.Context }};
  {{- end }}
{{- end }}
`

// Generator generates nginx configuration based on an observability policy.
type Generator struct {
	policies.UnimplementedGenerator

	telemetryConf dataplane.Telemetry
}

// NewGenerator returns a new instance of Generator.
func NewGenerator(telemetry dataplane.Telemetry) *Generator {
	return &Generator{telemetryConf: telemetry}
}

// GenerateForLocation generates policy configuration for a normal location block.
// For a normal location, all directives are applied.
// When the configuration involves a normal location redirecting to an internal location,
// only otel_trace and otel_trace_context are applied to the normal location.
func (g Generator) GenerateForLocation(pols []policies.Policy, location http.Location) policies.GenerateResultFiles {
	buildTemplate := func(
		tmplate *template.Template,
		fileSuffix string,
		includeGlobalAttrs bool,
	) policies.GenerateResultFiles {
		for _, pol := range pols {
			obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
			if !ok {
				continue
			}

			fields := map[string]any{
				"Tracing":  obs.Spec.Tracing,
				"Strategy": getStrategy(obs),
			}
			if includeGlobalAttrs {
				fields["GlobalSpanAttributes"] = g.telemetryConf.SpanAttributes
			}

			return policies.GenerateResultFiles{
				{
					Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_%s.conf", obs.Namespace, obs.Name, fileSuffix),
					Content: helpers.MustExecuteTemplate(tmplate, fields),
				},
			}
		}
		return nil
	}

	if location.Type == http.ExternalLocationType {
		return buildTemplate(tmpl, "ext", true)
	}

	return buildTemplate(tmplExtRedirect, "redirect", false)
}

// GenerateForInternalLocation generates policy configuration for an internal location block.
// otel_span_attr and otel_span_name are set in the internal location, with otel_trace and otel_trace_context
// being specified in the external location that redirects to the internal location.
func (g Generator) GenerateForInternalLocation(pols []policies.Policy) policies.GenerateResultFiles {
	for _, pol := range pols {
		obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
		if !ok {
			continue
		}

		fields := map[string]any{
			"Tracing":              obs.Spec.Tracing,
			"GlobalSpanAttributes": g.telemetryConf.SpanAttributes,
		}

		return policies.GenerateResultFiles{
			{
				Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_int.conf", obs.Namespace, obs.Name),
				Content: helpers.MustExecuteTemplate(tmplInternal, fields),
			},
		}
	}

	return nil
}

func getStrategy(obs *ngfAPIv1alpha2.ObservabilityPolicy) string {
	var strategy string
	if obs.Spec.Tracing != nil {
		switch obs.Spec.Tracing.Strategy {
		case ngfAPIv1alpha2.TraceStrategyParent:
			strategy = "$otel_parent_sampled"
		case ngfAPIv1alpha2.TraceStrategyRatio:
			strategy = "on"
			if obs.Spec.Tracing.Ratio != nil {
				if *obs.Spec.Tracing.Ratio > 0 {
					strategy = dataplane.CreateRatioVarName(*obs.Spec.Tracing.Ratio)
				} else {
					strategy = "off"
				}
			}
		default:
			strategy = "off"
		}
	}

	return strategy
}

	Valid bool
}

// EndpointPickerConfig represents the configuration for the EndpointPicker extension.
type EndpointPickerConfig struct {
	// EndpointPickerRef is the reference to the EndpointPicker.
	EndpointPickerRef *inference.EndpointPickerRef
	// NsName is the namespace of the EndpointPicker.
	NsName string
}

// VerifyTLS holds the backend TLS verification configuration.
type VerifyTLS struct {
	CertBundleID CertBundleID
	Hostname     string
	RootCAPath   string
}

// Telemetry represents global Otel configuration for the dataplane.
type Telemetry struct {
	// Endpoint specifies the address of OTLP/gRPC endpoint that will accept telemetry data.
	Endpoint string
	// ServiceName is the “service.name” attribute of the OTel resource.
	ServiceName string
	// Interval specifies the export interval.
	Interval string
	// Ratios is a list of tracing sampling ratios.
	Ratios []Ratio
	// SpanAttributes are global custom key/value attributes that are added to each span.
	SpanAttributes []SpanAttribute
	// BatchSize specifies the maximum number of spans to be sent in one batch per worker.
	BatchSize int32
	// BatchCount specifies the number of pending batches per worker, spans exceeding the limit are dropped.
	BatchCount int32
}

// SpanAttribute is a key value pair to be added to a tracing span.
type SpanAttribute struct {
	// Key is the key for a span attribute.
	Key string
	// Value is the value for a span attribute.
	Value string
}

// BaseHTTPConfig holds the configuration options at the http context.
type BaseHTTPConfig struct {
	// DNSResolver defines the DNS resolver configuration for NGINX.
	DNSResolver *DNSResolverConfig
	// Compression defines the compression settings for NGINX.
	Compression *CompressionSettings
	// AuthZConfigs holds the complete authorization configuration for JWT claims.
	AuthZConfigs []*AuthZConfig
	// DisableBaseProxySetHeaders specifies which default proxy_set_header entries should be omitted.
	DisableBaseProxySetHeaders []string
	// IPFamily specifies the IP family for all servers.
	IPFamily IPFamilyType
	// GatewaySecretID is the ID of the secret that contains the gateway backend TLS certificate.
	GatewaySecretID SSLKeyPairID
	// NginxReadinessProbePath is the path on which the health check endpoint for NGINX is exposed.
	NginxReadinessProbePath string
	// ServerTokens specifies the value for the server_tokens directive in NGINX configuration.
	ServerTokens string
	// Policies holds the policies attached to the Gateway for the http context.
	Policies []policies.Policy
	// Snippets contain the snippets that apply to the http context.
	Snippets []Snippet
	// RewriteClientIPSettings defines configuration for rewriting the client IP to the original client's IP.
	RewriteClientIPSettings RewriteClientIPSettings
	// NginxReadinessProbePort is the port on which the health check endpoint for NGINX is exposed.
	NginxReadinessProbePort int32
	// HTTP2 specifies whether http2 should be enabled for all servers.
	HTTP2 bool
	// DisableSNIHostValidation specifies if the SNI host validation should be disabled.
	DisableSNIHostValidation bool
}

// BaseStreamConfig holds the configuration options at the stream context.
type BaseStreamConfig struct {
	// DNSResolver specifies the DNS resolver configuration for ExternalName services.
	DNSResolver *DNSResolverConfig
}

