func telemetryEnabled(gw *graph.Gateway) bool {
	if gw == nil {
		return false
	}

	if gw.EffectiveNginxProxy == nil || gw.EffectiveNginxProxy.Telemetry == nil {
		return false
	}

	tel := gw.EffectiveNginxProxy.Telemetry

	if slices.Contains(tel.DisabledFeatures, ngfAPIv1alpha2.DisableTracing) {
		return false
	}

	if tel.Exporter == nil || tel.Exporter.Endpoint == nil {
		return false
	}

	return true
}

// buildTelemetry generates the Otel configuration.
func buildTelemetry(g *graph.Graph, gateway *graph.Gateway) Telemetry {
	if !telemetryEnabled(gateway) {
		return Telemetry{}
	}

	serviceName := fmt.Sprintf("ngf:%s:%s", gateway.Source.Namespace, gateway.Source.Name)
	telemetry := gateway.EffectiveNginxProxy.Telemetry
	if telemetry.ServiceName != nil {
		serviceName = serviceName + ":" + *telemetry.ServiceName
	}

	tel := Telemetry{
		Endpoint:    *telemetry.Exporter.Endpoint, // safe to deref here since we verified that telemetry is enabled
		ServiceName: serviceName,
	}

	if telemetry.Exporter.BatchCount != nil {
		tel.BatchCount = *telemetry.Exporter.BatchCount
	}
	if telemetry.Exporter.BatchSize != nil {
		tel.BatchSize = *telemetry.Exporter.BatchSize
	}
	if telemetry.Exporter.Interval != nil {
		tel.Interval = string(*telemetry.Exporter.Interval)
	}

	tel.SpanAttributes = setSpanAttributes(telemetry.SpanAttributes)

	// FIXME(sberman): https://github.com/nginx/nginx-gateway-fabric/issues/2038
	// Find a generic way to include relevant policy info at the http context so we don't need policy-specific
	// logic in this function
	ratioMap := make(map[string]int32)
	for _, pol := range g.NGFPolicies {
		if obsPol, ok := pol.Source.(*ngfAPIv1alpha2.ObservabilityPolicy); ok {
			if obsPol.Spec.Tracing != nil && obsPol.Spec.Tracing.Ratio != nil && *obsPol.Spec.Tracing.Ratio > 0 {
				ratioName := CreateRatioVarName(*obsPol.Spec.Tracing.Ratio)
				ratioMap[ratioName] = *obsPol.Spec.Tracing.Ratio
			}
		}
	}

	tel.Ratios = make([]Ratio, 0, len(ratioMap))
	for name, ratio := range ratioMap {
		tel.Ratios = append(tel.Ratios, Ratio{Name: name, Value: ratio})
	}

	return tel
}

func setSpanAttributes(spanAttributes []ngfAPIv1alpha1.SpanAttribute) []SpanAttribute {
	spanAttrs := make([]SpanAttribute, 0, len(spanAttributes))
	for _, spanAttr := range spanAttributes {
		sa := SpanAttribute{
			Key:   spanAttr.Key,
			Value: spanAttr.Value,
		}
		spanAttrs = append(spanAttrs, sa)
	}

	return spanAttrs
}

// CreateRatioVarName builds a variable name for an ObservabilityPolicy to be used with
// ratio-based trace sampling.
func CreateRatioVarName(ratio int32) string {
	return fmt.Sprintf("$otel_ratio_%d", ratio)
}

// buildBaseHTTPConfig generates the base http context config that should be applied to all servers.
func buildBaseHTTPConfig(
	gateway *graph.Gateway,
	gatewaySnippetsFilters map[types.NamespacedName]*graph.SnippetsFilter,
	gatewayRateLimitPolicies map[graph.PolicyKey]*graph.Policy,
) BaseHTTPConfig {
	baseConfig := BaseHTTPConfig{
		// HTTP2 should be enabled by default
		HTTP2:    true,
		IPFamily: Dual,
		Policies: buildPolicies(gateway, gateway.Policies),
		Snippets: buildSnippetsForContext(gatewaySnippetsFilters, ngfAPIv1alpha1.NginxContextHTTP),
	}

	// Create HTTP context policies for route-targeting RateLimitPolicies
	// For RateLimitPolicies that target routes that aren't attached to the Gateway,
	// these policies need to create the limit_req_zone directive at the http context.
	// To achieve this, we create a modified copy of the RateLimitPolicy with an annotation
	// indicating it's for HTTP context use only and attach it to the base HTTP config.
	httpContextRateLimitPolicies := buildHTTPContextRateLimitPolicies(gatewayRateLimitPolicies)
	baseConfig.Policies = append(baseConfig.Policies, httpContextRateLimitPolicies...)

	if gateway.Valid && gateway.SecretRef != nil {
		baseConfig.GatewaySecretID = generateSSLKeyPairID(*gateway.SecretRef)

	data []byte
}

// executeFunc is a function that generates NGINX configuration from internal representation.
type executeFunc func(configuration dataplane.Configuration) []executeResult

// Generate generates NGINX configuration files from internal representation.
// It is the responsibility of the caller to validate the configuration before calling this function.
// In case of invalid configuration, NGINX will fail to reload or could be configured with malicious configuration.
// To validate, use the validators from the validation package.
func (g GeneratorImpl) Generate(conf dataplane.Configuration) []agent.File {
	files := make([]agent.File, 0)

	for id, pair := range conf.SSLKeyPairs {
		files = append(files, generatePEM(id, pair.Cert, pair.Key))
	}

	policyGenerator := policies.NewCompositeGenerator(
		clientsettings.NewGenerator(),
		observability.NewGenerator(conf.Telemetry),
		snippetspolicy.NewGenerator(),
		proxysettings.NewGenerator(),
		ratelimit.NewGenerator(),
		waf.NewGenerator(),
	)

	files = append(files, g.executeConfigTemplates(conf, policyGenerator)...)

	for id, bundle := range conf.WAF.WAFBundles {
		files = append(files, generateWAFBundle(id, bundle))
	}

	for id, bundle := range conf.CertBundles {
		if id.IsCRLBundle() {
			files = append(files, generateCRLBundle(id, bundle))
		} else {
			files = append(files, generateCertBundle(id, bundle))
		}
	}

	for id, data := range conf.AuthSecrets {
		files = append(files, generateAuthFile(id, data))
	}
	return files
}

// GenerateDeploymentContext generates the deployment_ctx.json file needed for N+ licensing.
// It's exported since it's used by the init container process.
func (g GeneratorImpl) GenerateDeploymentContext(depCtx dataplane.DeploymentContext) (agent.File, error) {
	depCtxBytes, err := json.Marshal(depCtx)
	if err != nil {
		return agent.File{}, fmt.Errorf("error building deployment context for mgmt block: %w", err)
	}

	deploymentCtxFile := agent.File{
		Meta: &pb.FileMeta{
			Name:        mainIncludesFolder + "/deployment_ctx.json",
			Hash:        filesHelper.GenerateHash(depCtxBytes),
			Permissions: file.RegularFileMode,
			Size:        int64(len(depCtxBytes)),
		},
		Contents: depCtxBytes,
	}

	return deploymentCtxFile, nil
}

func (g GeneratorImpl) executeConfigTemplates(
	conf dataplane.Configuration,
	generator policies.Generator,
) []agent.File {
	fileBytes := make(map[string][]byte)

	httpUpstreams := g.createUpstreams(conf.Upstreams, upstreamsettings.NewProcessor())
	keepAliveCheck := newKeepAliveChecker(httpUpstreams)

	for _, execute := range g.getExecuteFuncs(generator, httpUpstreams, keepAliveCheck) {
		results := execute(conf)
		for _, res := range results {
			fileBytes[res.dest] = append(fileBytes[res.dest], res.data...)
		}
	}

	var mgmtFiles []agent.File
	if g.plus {
		mgmtFiles = g.generateMgmtFiles(conf)
	}

	files := make([]agent.File, 0, len(fileBytes)+len(mgmtFiles))
	for fp, bytes := range fileBytes {
		files = append(files, agent.File{
			Meta: &pb.FileMeta{
				Name:        fp,
				Hash:        filesHelper.GenerateHash(bytes),
				Permissions: file.RegularFileMode,
				Size:        int64(len(bytes)),
			},
			Contents: bytes,
		})
	}
	files = append(files, mgmtFiles...)

	return files
}

func (g GeneratorImpl) getExecuteFuncs(
	generator policies.Generator,
	upstreams []http.Upstream,
	keepAliveCheck keepAliveChecker,
) []executeFunc {
	return []executeFunc{
		newExecuteMainConfigFunc(generator),
		executeEventsConfig,
		newExecuteBaseHTTPConfigFunc(generator),
		g.newExecuteServersFunc(generator, keepAliveCheck),
		newExecuteUpstreamsFunc(upstreams),
		executeSplitClients,
		executeMaps,
		executeTelemetry,
		g.executeStreamServers,
		g.executeStreamUpstreams,
		executeStreamMaps,
		executePlusAPI,
	}
}

func generatePEM(id dataplane.SSLKeyPairID, cert []byte, key []byte) agent.File {
	c := make([]byte, 0, len(cert)+len(key)+1)
	c = append(c, cert...)
	c = append(c, '\n')

	IPv6 IPFamilyType = "ipv6"
)

// Ratio represents a tracing sampling ratio used in an nginx config with the otel_module.
type Ratio struct {
	// Name is based on the associated ObservabilityPolicy's NamespacedName,
	// and is used as the nginx variable name for this ratio.
	Name string
	// Value is the value of the ratio.
	Value int32
}

// Logging defines logging related settings for NGINX.
type Logging struct {
	// AccessLog defines the configuration for the NGINX access log.
	AccessLog *AccessLog
	// ErrorLevel defines the error log level.
	ErrorLevel string
	// ErrorLogFormat defines the error log format.
	// If not specified, the default NGINX error log format is used.

