15	// Validator validates an ObservabilityPolicy.
16	// Implements policies.Validator interface.
17	type Validator struct {
18		genericValidator validation.GenericValidator
19	}
20	
21	// NewValidator returns a new instance of Validator.
22	func NewValidator(genericValidator validation.GenericValidator) *Validator {
23		return &Validator{genericValidator: genericValidator}
24	}
25	
26	// Validate validates the spec of an ObservabilityPolicy.
27	func (v *Validator) Validate(policy policies.Policy) []conditions.Condition {
28		obs := helpers.MustCastObject[*ngfAPIv1alpha2.ObservabilityPolicy](policy)
29	
30		targetRefPath := field.NewPath("spec").Child("targetRefs")
31		supportedKinds := []gatewayv1.Kind{kinds.HTTPRoute, kinds.GRPCRoute}
32		supportedGroups := []gatewayv1.Group{gatewayv1.GroupName}
33	
34		for _, ref := range obs.Spec.TargetRefs {
35			if err := policies.ValidateTargetRef(ref, targetRefPath, supportedGroups, supportedKinds); err != nil {
36				return []conditions.Condition{conditions.NewPolicyInvalid(err.Error())}
37			}
38		}
39	
40		if err := v.validateSettings(obs.Spec); err != nil {
41			return []conditions.Condition{conditions.NewPolicyInvalid(err.Error())}
42		}
43	
44		return nil
45	}
46	
47	// ValidateGlobalSettings validates an ObservabilityPolicy with respect to the NginxProxy global settings.
48	func (v *Validator) ValidateGlobalSettings(
49		_ policies.Policy,
50		globalSettings *policies.GlobalSettings,
51	) []conditions.Condition {
52		if globalSettings == nil {
53			return []conditions.Condition{
54				conditions.NewPolicyNotAcceptedNginxProxyNotSet(conditions.PolicyMessageNginxProxyInvalid),
55			}
56		}
57	
58		if !globalSettings.TelemetryEnabled {
59			return []conditions.Condition{
60				conditions.NewPolicyNotAcceptedNginxProxyNotSet(conditions.PolicyMessageTelemetryNotEnabled),
61			}
62		}
63	
64		return nil
65	}
66	
67	// Conflicts returns true if the two ObservabilityPolicies conflict.
68	func (v *Validator) Conflicts(polA, polB policies.Policy) bool {
69		a := helpers.MustCastObject[*ngfAPIv1alpha2.ObservabilityPolicy](polA)
70		b := helpers.MustCastObject[*ngfAPIv1alpha2.ObservabilityPolicy](polB)
71	
72		return a.Spec.Tracing != nil && b.Spec.Tracing != nil
73	}
74	
75	func (v *Validator) validateSettings(spec ngfAPIv1alpha2.ObservabilityPolicySpec) error {
76		var allErrs field.ErrorList
77		fieldPath := field.NewPath("spec")
78	
79		if spec.Tracing != nil {
80			tracePath := fieldPath.Child("tracing")
81	
82			switch spec.Tracing.Strategy {
83			case ngfAPIv1alpha2.TraceStrategyRatio, ngfAPIv1alpha2.TraceStrategyParent:
84			default:
85				allErrs = append(
86					allErrs,
87					field.NotSupported(
88						tracePath.Child("strategy"),
89						spec.Tracing.Strategy,
90						[]string{
91							string(ngfAPIv1alpha2.TraceStrategyRatio),
92							string(ngfAPIv1alpha2.TraceStrategyParent),
93						}),
94				)
95			}
96	
97			if spec.Tracing.Context != nil {
98				switch *spec.Tracing.Context {
99				case ngfAPIv1alpha2.TraceContextExtract,
100					ngfAPIv1alpha2.TraceContextInject,
101					ngfAPIv1alpha2.TraceContextPropagate,
102					ngfAPIv1alpha2.TraceContextIgnore:
103				default:
104					allErrs = append(
105						allErrs,
106						field.NotSupported(
107							tracePath.Child("context"),
108							spec.Tracing.Context,
109							[]string{
110								string(ngfAPIv1alpha2.TraceContextExtract),
111								string(ngfAPIv1alpha2.TraceContextInject),
112								string(ngfAPIv1alpha2.TraceContextPropagate),
113								string(ngfAPIv1alpha2.TraceContextIgnore),
114							}),
115					)
116				}
117			}
118	
119			if spec.Tracing.SpanName != nil {
120				if err := v.genericValidator.ValidateEscapedStringNoVarExpansion(*spec.Tracing.SpanName); err != nil {
121					allErrs = append(
122						allErrs,
123						field.Invalid(tracePath.Child("spanName"), *spec.Tracing.SpanName, err.Error()),
124					)
125				}
126			}
127	
128			if spec.Tracing.SpanAttributes != nil {
129				spanAttrPath := tracePath.Child("spanAttributes")
130				for _, spanAttr := range spec.Tracing.SpanAttributes {
131					if err := v.genericValidator.ValidateEscapedStringNoVarExpansion(spanAttr.Key); err != nil {
132						allErrs = append(allErrs, field.Invalid(spanAttrPath.Child("key"), spanAttr.Key, err.Error()))
133					}
134	
135					if err := v.genericValidator.ValidateEscapedStringNoVarExpansion(spanAttr.Value); err != nil {
136						allErrs = append(allErrs, field.Invalid(spanAttrPath.Child("value"), spanAttr.Value, err.Error()))
137					}
138				}
139			}
140		}
141	
142		return allErrs.ToAggregate()
143	}
